// Neither n8n's cron history nor Paragraph give us a "since" filter,
// so track the newest post id we've already alerted on in this node's
// workflow static data and only emit posts published after it.
// First-ever run seeds the seen-list from the current post set instead
// of firing a backlog blast for every historical newsletter issue.
const staticData = $getWorkflowStaticData('node');

const body = $input.first().json || {};
const posts = body.posts || body.data || (Array.isArray(body) ? body : []);

const normalized = posts.map((p) => ({
  id: p.id || p.postId || p.slug,
  title: p.title || '(untitled)',
  subtitle: p.subtitle || p.excerpt || '',
  url: p.url || p.postUrl || (p.slug ? `https://paragraph.com/@thezao/${p.slug}` : ''),
  publishedAt: p.publishedAt || p.createdAt || p.updatedAt || null
})).filter((p) => p.id);

normalized.sort((a, b) => new Date(b.publishedAt || 0) - new Date(a.publishedAt || 0));

if (!staticData.seenIds) {
  // First run: seed with everything currently published, emit nothing.
  staticData.seenIds = normalized.map((p) => p.id);
  return [];
}

const seen = new Set(staticData.seenIds);
const fresh = normalized.filter((p) => !seen.has(p.id));

fresh.forEach((p) => seen.add(p.id));
staticData.seenIds = Array.from(seen).slice(-200);

return fresh.map((p) => ({ json: p }));

// n8n stays plumbing here: template-based per-platform draft copy,
// no AI generation (that reasoning step belongs to ZOE, not this workflow).
return $input.all().map((item) => {
  const { title, subtitle, url } = item.json;

  const x = `New from The ZAO: ${title}\n\nRead -> ${url}`;
  const farcaster = `${title} just dropped\n\n${url}`;
  const discord = `**${title}**\n${subtitle}\n\n${url}`;
  const telegram = `${title}\n\n${url}`;
  const linkedin = `Excited to share our latest newsletter: ${title}.\n\n${subtitle}\n\nRead the full issue: ${url}`;
  const facebook = `New issue is live: ${title}\n\n${url}`;

  const draftMessage = [
    `Draft cross-posts for: ${title}`,
    '',
    `[X]\n${x}`,
    '',
    `[Farcaster]\n${farcaster}`,
    '',
    `[Discord]\n${discord}`,
    '',
    `[Telegram]\n${telegram}`,
    '',
    `[LinkedIn]\n${linkedin}`,
    '',
    `[Facebook]\n${facebook}`
  ].join('\n');

  return { json: { title, url, draftMessage } };
});
